import{d as e,p as t}from"./createLucideIcon-CAfTkhdV.js";var n=[{id:`blind-by-design`,title:`Blind by Design`,month:`MAY 2026`,story:`Three levels of OpenFeature with flagd as the provider, in a Java + Spring Boot service. Wire the SDK against a flagd sidecar (Beginner), layer evaluation context to target by cohort (Intermediate), then instrument flag evaluations with OpenTelemetry and roll back a misbehaving fractional rollout (Expert). All without redeploying.`,tags:[`OpenFeature`,`flagd`,`Spring Boot`,`Java`,`OpenTelemetry`,`Grafana`],contributor:{name:`Simon Schrottner`,url:`https://schrottner.at/`,about:`CNCF Ambassador and maintainer of OpenFeature and JUnit Pioneer. Helps teams release faster and with more confidence through open standards, feature flagging, and the communities that make both possible. A familiar face at KubeCon EU, Devoxx, ContainerDays, and meetups across Europe.`},backstory:[`The Aletheia Institute is running a multi-phase vision-enhancement trial. The lab is a Spring Boot service whose one job is to record the vision_state of every subject who walks through the protocol (blurry, sharp, enhanced, or clouded), because subjects don't all arrive with the same biology, the same dose adherence, or the same trial-jurisdiction baseline. The flag definitions that drive those readings live in flags.json, watched by a flagd sidecar; the OpenFeature SDK is supposed to call that sidecar on every evaluation.`,`It hasn't been. For the past eight months, every subject through the door has been recorded as "untreated": the integration was never finished, and the lab director assumed the system was reading the chart. Worse, eight weeks ago the Institute opened its flagship Phase 3 trial: a new amplifier variant rolled out fractionally to a cohort by a targeting rule in flags.json. Four adverse-event reports have since been filed, each one a subject whose vision_state at discharge was worse than at enrollment.`,`The monitoring is dark, not by accident, but because no one ever turned the lights on. Your mission across three levels: stand up the lab so it reads the chart, read the chart by cohort so outcomes can be tracked, then turn on the lights and roll back the Phase 3 variant before the director signs off on the next enrollment batch.`],context:{title:`What you'll be using`,body:[`OpenFeature is a vendor-neutral standard for feature flags. The reference cloud-native implementation is flagd, which serves flag definitions from a JSON file, locally or remotely, and the OpenFeature SDK in your application calls it on every evaluation.`,`In this adventure, the lab uses OpenFeature exactly the way a real engineering team would: a Spring Boot service holds the SDK client, flagd holds the flag definitions, and the targeting rules in flags.json decide what reading every subject ends up with. By the end, you'll have wired the SDK in from scratch, learned to record outcomes by cohort, and rolled back a misbehaving Phase 3 trial without redeploying.`]},rewards:{deadline:`26 May 2026 at 23:59 CET`,eligibility:`Complete all levels and post your solution in the community before the deadline to be eligible.`,tiers:[{label:`1st place`,description:`50% voucher for a Linux Foundation certification`},{label:`Top 3`,description:`Credly badge to showcase the achievement`}],rankingNote:`Ranking is determined by total points across all three levels. Points per level are awarded by submission order within the active week (100 for the first valid solution, 95 for the second, and so on; late submissions still earn 60).`,rankingRulesUrl:`${t}/t/about-the-challenges-category/16`},levels:[{id:`beginner`,name:`Stand up the Lab`,difficulty:`Beginner`,topics:[`OpenFeature`,`flagd`,`Spring Boot`],audience:`Platform engineers, SREs, and developers curious about feature flags, with no prior OpenFeature experience needed, but familiarity with Spring Boot and basic Java will help.`,learnings:[`How an OpenFeature client and provider work together: the SDK is provider-agnostic and the flagd provider plugs in via dependency only`,`What remote provider means in practice: the SDK calls a separate flag service (flagd) over gRPC, not parsing flags.json itself`,`What flags.json looks like for flagd (state, variants, defaultVariant)`,`Why hot-reload of the flag file matters operationally: configuration without redeploy`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F04-blind-by-design_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/wire-openfeature-flagd-into-a-spring-boot-service-with-zero-setup-adventure-04-beginner/1419`,deadline:`26 May 2026 at 23:59 CET`,intro:[`Wire the OpenFeature Java SDK and the flagd contrib provider into a Spring Boot service so flag evaluations are resolved by a flagd sidecar against a flags.json file. Author your first flag, then prove that editing flags.json flips the response on the next request: no app restart, no flagd restart, no redeploy.`],backstory:[`The lab is on its first shift and it isn't reading the chart. Every subject who walks through the door gets the same hard-coded reading on their record, no matter what the lab director just signed off on. The label coming out of the lab is a literal string baked into the controller, not a reading pulled from the chart.`,`Your mission: replace that hard-coded label with an OpenFeature client, point that client at the flagd sidecar that already runs next to your Codespace, and let flags.json drive what gets recorded as the subject's vision_state. Prove the lab can change what it records without restarting anything.`],objective:[`curl http://localhost:8080/ returns a vision_state reading resolved from flags.json (not the hard-coded 'untreated' fallback)`,`The response payload includes OpenFeature evaluation details: flag key, variant, reason, and value`,`Editing flags.json to change defaultVariant causes the next request to return the new variant without restarting the app or flagd`],architecture:[`This level runs as two containers side-by-side in your Codespace: the Spring Boot lab and a flagd sidecar.`,`The Spring Boot service runs on http://localhost:8080/ with one endpoint, GET /. flags.json is mounted read-only into the flagd sidecar; edit it through the IDE and flagd's file watcher picks up the change within about a second. The flagd sidecar serves flag evaluations over gRPC on :8013. The OpenFeature SDK reads FLAGD_HOST and FLAGD_PORT from the environment (pre-set by the devcontainer), so there is no host or port to hard-code.`],toolbox:[{name:`./mvnw`,description:`Maven wrapper checked in next to pom.xml, builds and runs the Spring Boot lab`},{name:`curl`,description:`makes requests to http://localhost:8080/ and shows the reading the lab records`,url:`https://curl.se/`},{name:`jq`,description:`pretty-prints and filters the JSON evaluation details returned by the SDK`,url:`https://jqlang.org/`},{name:`flagd sidecar`,description:`already running in the devcontainer compose stack on the docker-internal network, no port forwarding needed`}],howToPlay:[{title:`Start the Lab`,body:"Run the lab from the terminal, or press F5 in VS Code with `Laboratory.java` open. The lab starts in the broken state, returning the hard-coded 'untreated' response:\n\n```sh\n./mvnw spring-boot:run\n```\n"},{title:`Confirm the Broken State`,body:`Open the Ports tab, set port 8080 to Public, then click the forwarded address to confirm the hard-coded 'untreated' response.`},{title:`Add Dependencies`,body:"Add the OpenFeature Java SDK and flagd contrib provider to `pom.xml`. GroupIds, artifactIds, and versions are in the OpenFeature Java SDK docs and the flagd Java provider README."},{title:`Configure the Provider`,body:"Create a Spring `@Configuration` class that builds a `FlagdProvider` in RPC mode and registers it on the OpenFeature API at startup. No host or port to configure: the devcontainer pre-sets `FLAGD_HOST` and `FLAGD_PORT`."},{title:`Author Your First Flag`,body:"Open `flags.json` and add a flag named `vision_state` with two string variants (for example 'blurry' and 'clouded') and a `defaultVariant`. flagd's file watcher picks up changes within about a second, no restart needed."},{title:`Wire the Evaluation`,body:"Replace the hard-coded return in `Trial` with an OpenFeature evaluation of `vision_state`, returning the full evaluation details (flag key, variant, value, reason)."},{title:`Test Hot Reload`,body:"Restart the lab. Confirm the value resolves from `flags.json`, then edit `flags.json`, change `defaultVariant`, save, and re-run curl without restarting anything:\n\n```sh\ncurl -s http://localhost:8080/ | jq\n```\n"}],helpfulLinks:[{label:`OpenFeature Java SDK`,url:`https://openfeature.dev/docs/reference/technologies/server/java/`},{label:`flagd Java provider`,url:`https://github.com/open-feature/java-sdk-contrib/tree/main/providers/flagd`},{label:`flagd flag definitions`,url:`https://flagd.dev/reference/flag-definitions/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`}},{id:`intermediate`,name:`Outcome by Cohort`,difficulty:`Intermediate`,topics:[`OpenFeature`,`flagd`,`Spring Boot`,`Java`],learnings:[`How evaluation context works in OpenFeature: passing runtime attributes (user ID, cohort, region) to influence flag resolution`,`How to configure flagd targeting rules to route specific cohorts to specific flag variants without code changes`,`Why cohort-based rollouts reduce blast radius: only the targeted segment sees the new behaviour`,`How to verify targeting is working correctly by inspecting flag evaluation results per context`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F04-blind-by-design_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/outcome-by-cohort-adventure-04-intermediate/1485`,deadline:`26 May 2026 at 23:59 CET`,intro:[`Populate all three OpenFeature evaluation-context layers on a Spring Boot service and register a custom Hook.`,`Transaction context (request-scoped) is populated by a Spring HandlerInterceptor that reads ?species= and clears on afterCompletion so values don't leak across pooled threads. Global context (process-scoped) is set once at startup from the COUNTRY environment variable. Invocation context (call-site) is passed as the third argument to client.getStringDetails(), carrying the per-evaluation dose attribute. An Audit Hook fires after every evaluation and writes an [AUDIT] log line with a fixed PII-safe attribute allowlist.`,`The broken-state lab already has the SDK and flagd provider wired in Resolver.RPC mode. The targeting in flags.json already carries three branches (species == zyklop, improper dose for non-zyklops, country == de), but none of those attributes are in the eval context yet, so every request lands on the default variant. Your job: make the targeting fire by wiring the three context layers and the audit hook.`],backstory:[`The trial is widening. Subjects from outside the lab's local population are getting the wrong reading on their chart, and the lab director has just walked in holding a stack of complaint forms. She wants the audit log to tell her, after the fact, exactly which vision_state the lab recorded for which subject, and she wants the lab to read the chart properly before it records any more bad readings.`,`The protocol is the same for every subject; the lab is not varying the trial. What differs is the observed outcome: some subjects have a biology that responds enhancedly to the same serum, some absorb less or more than the protocol's standard dose, and the trial is registered in different jurisdictions with different baselines.`,`Your shift: teach the lab to read each subject's species off the request, attach the trial's country of registration (set on the JVM via the COUNTRY environment variable) to the global context, pass the dose as invocation context at the moment of the flag evaluation, and register an audit hook that records every dose with its variant and reason.`],objective:[`curl /?species=zyklop returns 'enhanced' regardless of dose or country`,`With COUNTRY=de, curl /?dose=standard returns 'sharp'; with COUNTRY=at, the same call falls through to the default`,`curl /?dose=underdose returns 'clouded'; curl /?species=zyklop&dose=underdose returns 'enhanced' (species takes precedence)`,`Every evaluation produces an [AUDIT] log line naming the flag, the resolved variant, the reason, and the attributes that drove the outcome`,`The response is never 'untreated' (that fallback only fires when the SDK cannot reach flagd)`],architecture:[`The lab and a flagd sidecar run as siblings in the devcontainer's compose stack. The OpenFeature client uses Resolver.RPC to reach flagd:8013; flagd watches flags.json and serves evaluations from it.`,`Three context layers merge before flagd evaluates the targeting rules: global context (country, set at startup), transaction context (species, set per request by the interceptor), and invocation context (dose, passed at the call site). Precedence on conflict: invocation > transaction > global.`],architectureDiagram:`/pr-preview/pr-72/assets/blind-by-design-intermediate-DdSTFQMV.svg`,diagramAlt:`HTTP flows through SpeciesInterceptor, Trial, and OpenFeature client left to right, then down through AuditHook and FlagdProvider, connecting via gRPC to a flagd sidecar.`,toolbox:[{name:`Java 21 (Temurin)`,description:`pre-installed in the devcontainer`},{name:`./mvnw`,description:`Spring Boot Maven Wrapper, no global Maven install required`},{name:`curl`,description:`sends requests to http://localhost:8080/ to test each targeting branch`,url:`https://curl.se/`},{name:`jq`,description:`pretty-prints the JSON evaluation details`,url:`https://jqlang.org/`}],howToPlay:[{title:`Wait for Setup`,body:`Wait ~2-3 minutes for the Java toolchain to install.`},{title:`Confirm the Broken State`,body:`Start the lab and confirm the broken state, where no targeting fires yet. Stop the app and start fixing:

\`\`\`sh
./mvnw spring-boot:run
curl 'http://localhost:8080/?species=zyklop'
# returns 'blurry', wrong cohort, targeting can't fire
\`\`\`
`},{title:`Inspect the Targeting Rules`,body:'Open `flags.json` and inspect the targeting. Three branches exist but none fire because nothing in the app populates the attributes yet:\n\n```json\n"targeting": {\n  "if": [\n    { "===": [{"var": "species"}, "zyklop"] },        "enhanced",\n    { "in":  [{"var": "dose"}, ["underdose", "overdose"]] }, "clouded",\n    { "===": [{"var": "country"}, "de"] },             "sharp"\n  ]\n}\n```\n\nYour job: populate `species`, `country`, and `dose` on the evaluation context so the targeting fires.\n'},{title:`Build the SpeciesInterceptor`,body:"Create a Spring `HandlerInterceptor` named `SpeciesInterceptor`: in `preHandle`, read `?species=` and put it on the transaction context; in `afterCompletion`, clear the context so values do not leak across pooled threads. Register a `ThreadLocalTransactionContextPropagator` once on the OpenFeature API in a static initializer."},{title:`Wire OpenFeatureConfig`,body:"Update `OpenFeatureConfig` to: register `SpeciesInterceptor` with Spring (`WebMvcConfigurer.addInterceptors`), read the `COUNTRY` environment variable and set it as the global evaluation context, and register `AuditHook` globally on the OpenFeature API."},{title:`Update the Trial`,body:"Update `Trial` so each evaluation passes `dose` on the invocation context (the third argument to `client.getStringDetails`). Default to 'standard', but make it overridable via `?dose=` so you can test each branch by hand."},{title:`Implement AuditHook`,body:"Implement `AuditHook`: in `after()`, write an `[AUDIT]` log line with flag name, variant, reason, and a fixed allowlist of attributes (species, country, dose). Log at WARN when the variant is 'clouded', otherwise INFO. Implement `error()` so failed evaluations are not silent."},{title:`Test All Targeting Branches`,body:`Run the lab with country-specific scripts. These pipe output through \`tee app.log\`, which the verifier needs:

\`\`\`sh
./run-germany.sh   # COUNTRY=de
./run-austria.sh   # COUNTRY=at
\`\`\`

In another terminal, verify each branch:

\`\`\`sh
curl -s 'http://localhost:8080/?species=zyklop' | jq .value
# => "enhanced"

curl -s 'http://localhost:8080/?dose=standard' | jq .value
# => "sharp" (Germany) / "blurry" (Austria)

curl -s 'http://localhost:8080/?dose=underdose' | jq .value
# => "clouded"

curl -s 'http://localhost:8080/?species=zyklop&dose=underdose' | jq .value
# => "enhanced" (species wins)
\`\`\`

Check the audit trail:

\`\`\`sh
grep '\\[AUDIT\\]' app.log | head
\`\`\`
`}],helpfulLinks:[{label:`OpenFeature Java SDK`,url:`https://openfeature.dev/docs/reference/technologies/server/java/`},{label:`OpenFeature Hooks`,url:`https://openfeature.dev/docs/reference/concepts/hooks`},{label:`Spring HandlerInterceptor`,url:`https://docs.spring.io/spring-framework/docs/current/javadoc-api/org/springframework/web/servlet/HandlerInterceptor.html`},{label:`flagd flag definitions`,url:`https://flagd.dev/reference/flag-definitions/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`}}]},{id:`building-cloudhaven`,title:`Building CloudHaven`,month:`JAN 2026`,story:`Join the Infrastructure Guild and modernize CloudHaven's infrastructure from manual provisioning to a self-service platform using Infrastructure as Code. A hands-on journey through infrastructure as code with OpenTofu and GitHub Actions.`,tags:[`OpenTofu`,`Terraform`,`GitHub Actions`,`Trivy`,`TDD`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,about:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`Welcome to CloudHaven, a bustling digital metropolis where every district depends on essential services to thrive. You've just joined the Infrastructure Guild, a team of platform engineers responsible for providing the tools and services that keep the city running.`,`CloudHaven is expanding rapidly. The Merchant's Quarter needs storage vaults for their goods and ledgers for tracking inventory. The Scholar's District requires secure archives for ancient texts. The Artisan's Quarter demands workshops with specialized tools. Each district has unique needs, but they all depend on the Guild to provide reliable, scalable infrastructure services.`,`The Guild used to provision everything manually through cloud consoles, a process that was slow, error-prone, and impossible to track. Recently, they've started adopting Infrastructure as Code, but the transition is incomplete.`,`The Guild Master has assigned you to complete the modernization journey.`,`Your mission: build the services and tools that will support CloudHaven's future growth.`],levels:[{id:`beginner`,name:`The Foundation Stones`,difficulty:`Beginner`,topics:[`OpenTofu`],learnings:[`Infrastructure as Code with OpenTofu`,`Remote state management with GCS backend`,`Dynamic resource provisioning with for_each`,`Conditional resources with the enabled meta-argument, new in OpenTofu`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F02-building-cloudhaven_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/practice-infrastructure-as-code-with-zero-setup-adventure-02-beginner/656`,deadline:`4 February 2026 at 23:59 CET`,intro:[`An incomplete OpenTofu configuration is blocking the Merchant's Quarter from going live. Fix the broken backend, wire up dynamic resource provisioning with for_each, and use the new enabled meta-argument to conditionally deploy the audit database.`],backstory:[`The Merchant's Quarter needs essential services, but the previous Guild engineer left the OpenTofu configuration incomplete and misconfigured. The state is stored locally, making collaboration impossible, and some services remain half-configured or missing.`,`Your mission: fix the issues, complete the setup, and establish proper infrastructure management for the Guild.`],objective:[`Provision storage vaults and ledger databases for each district dynamically`,`Deploy the audit database only when there is more than one district`,`Store state remotely in a GCS backend following best practices so the Guild can collaborate`,`Resolve all TODOs in the code and successfully run tofu apply`],toolbox:[{name:`tofu`,description:`OpenTofu CLI for infrastructure provisioning`,url:`https://opentofu.org/`},{name:`gcp-api-mock`,description:`mock GCP API running locally to simulate cloud resources without real cloud costs (Cloud Storage and Cloud SQL only)`,url:`https://github.com/KatharinaSick/gcp-api-mock`}],howToPlay:[{title:`Wait for the Environment`,body:`Wait ~2 minutes for the environment to initialize.`},{title:`Explore the Mock API`,body:`Open the Ports tab, find the GCP API Mock at port 30104. Use it to explore the mock cloud resources created by your configuration.`},{title:`Find the TODOs`,body:'All OpenTofu files are in `adventures/02-building-cloudhaven/beginner/`. Run:\n\n```sh\ngrep -r "TODO" .\n```\n\nFiles to review: `main.tf`, `state.tf`, `variables.tf`, `merchants.tf`, `audit.tf`, `outputs.tf`.'},{title:`Apply the Configuration`,body:"After fixing the TODOs, run:\n\n```sh\ntofu apply\n```\n\nIf you changed the backend configuration, run `tofu init -migrate-state` first."},{title:`Run the Smoke Test`,body:"Run the smoke test to verify your solution:\n\n```sh\n./smoke-test.sh\n```"}],helpfulLinks:[{label:`OpenTofu documentation`,url:`https://opentofu.org/docs/`},{label:`OpenTofu meta-arguments`,url:`https://opentofu.org/docs/language/meta-arguments/count/`},{label:`OpenTofu backend configuration`,url:`https://opentofu.org/docs/language/settings/backends/configuration/`},{label:`Google Cloud provider`,url:`https://registry.terraform.io/providers/hashicorp/google/latest/docs`}],verification:{command:`./smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`}},{id:`intermediate`,name:`The Modular Metropolis`,difficulty:`Intermediate`,topics:[`OpenTofu`,`TDD`],learnings:[`OpenTofu module testing with tofu test`,`Test-Driven Development (TDD) workflow`,`Input validation with custom rules`,`Refactoring infrastructure safely with moved blocks`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F02-building-cloudhaven_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/adventure-02-building-cloudhaven-intermediate-the-modular-metropolis/723/10`,deadline:`4 February 2026 at 23:59 CET`,intro:[`A senior engineer wrote the tests first and then left. The module code is buggy and the integration test is incomplete. Fix the implementation to match the test expectations, complete the end-to-end test, and use moved blocks to refactor without destroying state.`],backstory:[`After fixing the Foundation Stones, CloudHaven is thriving. The city has grown to three districts, and the Guild decided to refactor the infrastructure into reusable modules.`,`A senior engineer started the work using Test-Driven Development, writing tests first then implementing. But they were called away before finishing, leaving behind working tests and buggy code that doesn't match them.`,`Your mission: fix the bugs, complete the integration test, and deploy the infrastructure.`],objective:[`All tests of the districts module pass`,`A completed integration test that applies infrastructure against the mock GCP API to verify end-to-end functionality`,`Three districts deployed with correctly configured infrastructure (vaults and ledgers)`],toolbox:[{name:`tofu`,description:`OpenTofu CLI for infrastructure provisioning`,url:`https://opentofu.org/`},{name:`gcp-api-mock`,description:`mock GCP API running locally to simulate cloud resources without real cloud costs (Cloud Storage and Cloud SQL only)`,url:`https://github.com/KatharinaSick/gcp-api-mock`}],howToPlay:[{title:`Wait for the Environment`,body:`Wait ~2 minutes for the environment to initialize.`},{title:`Explore the Mock API`,body:`Open the Ports tab, find the GCP API Mock at port 30104. Use it to explore mock cloud resources.`},{title:`Fix the Failing Tests`,body:`All files are in \`adventures/02-building-cloudhaven/intermediate/\`. The tests define the expected behaviour: your job is to fix the implementation to match what the tests expect. Don't modify existing tests unless a comment tells you to.

\`\`\`
adventures/02-building-cloudhaven/intermediate/
├── main.tf                    # Provider and backend configuration
├── variables.tf               # Input variables
├── districts.tf               # Module calls for each district
├── outputs.tf                 # Infrastructure outputs
├── moved.tf                   # Resource migration blocks
├── modules/district/          # The district module (fix bugs here)
│   ├── main.tf                # Locals and tier configuration
│   ├── variables.tf           # Input validation
│   ├── vault.tf               # Storage bucket resource
│   ├── ledger.tf              # Cloud SQL resource
│   ├── outputs.tf             # Module outputs
│   └── tests/                 # Module tests (read these!)
└── tests/
    └── integration.tftest.hcl # Complete this test
\`\`\`

Run tests to see what fails:

\`\`\`sh
make test
\`\`\``},{title:`Apply the Infrastructure`,body:"Once all tests pass, apply the infrastructure:\n\n```sh\nmake test\nmake apply\n```"},{title:`Run the Smoke Test`,body:"Run the smoke test to verify your solution:\n\n```sh\n./smoke-test.sh\n```"}],helpfulLinks:[{label:`OpenTofu testing`,url:`https://opentofu.org/docs/cli/commands/test/`},{label:`OpenTofu modules`,url:`https://opentofu.org/docs/language/modules/`},{label:`Input validation rules`,url:`https://opentofu.org/docs/language/values/variables/#custom-validation-rules`},{label:`Moved blocks`,url:`https://opentofu.org/docs/language/modules/develop/refactoring/`}],verification:{command:`./smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`}},{id:`expert`,name:`The Guardian Protocols`,difficulty:`Expert`,topics:[`OpenTofu`,`GitHub Actions`,`Trivy`],learnings:[`GitHub Actions for drift detection and plan/apply`,`Integration tests with service containers`,`Security scanning with Trivy`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F02-building-cloudhaven_03-expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/adventure-02-building-cloudhaven-expert-the-guardian-protocols/782/8`,deadline:`4 February 2026 at 23:59 CET`,intro:[`Three broken GitHub Actions workflows stand between CloudHaven and automated infrastructure governance. Fix drift detection that creates PRs, PR validation with Trivy security scanning and service-container integration tests, and automatic apply on merge.`],backstory:[`After the Modular Metropolis refactoring, CloudHaven flourished. But with growth came risk. One night, a rogue change slipped through unnoticed and nearly brought down the North Market's trading vaults. The Council was furious: how could this happen without anyone noticing?`,`The Guild Master summoned you urgently. "We need guardians," she said. "Automated sentinels that watch over our infrastructure day and night. They must catch dangerous changes before they reach the city, detect when reality drifts from our blueprints, and sound the alarm when threats appear."`,`A previous engineer began building these Guardian Protocols using GitHub Actions, but was reassigned before completing them. The workflows exist, but they're incomplete and broken.`,`Your mission: bring the Guardian Protocols online and protect CloudHaven from chaos.`],objective:[`Drift detection: run tofu plan and create a PR when drift is found`,`PR validation: run tofu plan and comment results, run integration tests against the mock GCP API, scan for security vulnerabilities with Trivy and fail on critical or high severity issues`,`Automatic apply: apply infrastructure when a PR is merged to main`,`All three workflows must have succeeded at least once`],toolbox:[{name:`tofu`,description:`OpenTofu CLI for infrastructure provisioning`,url:`https://opentofu.org/`},{name:`gcp-api-mock`,description:`mock GCP API running locally (port set to public so GitHub Actions runners can access it)`,url:`https://github.com/KatharinaSick/gcp-api-mock`},{name:`GitHub Actions`,description:`the workflows you will fix are in .github/workflows/`,url:`https://docs.github.com/en/actions`}],howToPlay:[{title:`Wait for the Environment`,body:`Wait ~2 minutes for the environment to initialize.`},{title:`Check the Mock API`,body:`Open the Ports tab, find the GCP API Mock at port 30104. The port is set to public so GitHub Actions runners can reach the mock API during workflow runs.`},{title:`Fix the Workflows`,body:"Fix the three workflows in `.github/workflows/`:\n\n- `adventure02-expert-detect-drift.yaml`\n- `adventure02-expert-validate-changes.yaml`\n- `adventure02-expert-apply-infrastructure.yaml`\n\nThe OpenTofu configuration is correct, focus only on the workflow files."},{title:`Trigger Drift Detection`,body:`Commit and push to main. Go to the Actions tab, select the drift detection workflow, and click Run workflow. The infrastructure has intentional drift, so the workflow should create a draft PR.`},{title:`Trigger Validation`,body:`Click Ready for Review on the draft PR to trigger the validation workflow. To re-trigger validation after pushing new changes, convert the PR back to draft then ready for review again.`},{title:`Merge and Apply`,body:`When the PR is merged to main, the apply workflow runs automatically.`},{title:`Run the Smoke Test`,body:"Run the smoke test to verify your solution:\n\n```sh\ncd adventures/02-building-cloudhaven/expert\n./smoke-test.sh\n```"}],helpfulLinks:[{label:`GitHub Actions documentation`,url:`https://docs.github.com/en/actions`},{label:`GitHub Actions service containers`,url:`https://docs.github.com/en/actions/use-cases-and-examples/using-containerized-services/about-service-containers`},{label:`OpenTofu plan command`,url:`https://opentofu.org/docs/cli/commands/plan/`},{label:`Trivy action`,url:`https://github.com/aquasecurity/trivy-action`},{label:`TF-via-PR action`,url:`https://github.com/OP5dev/TF-via-PR`}],verification:{command:`./smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`}}]},{id:`echoes-lost-in-orbit`,title:`Echoes Lost in Orbit`,month:`DEC 2025`,story:`Restore interstellar communications by fixing broken GitOps setups, progressive delivery systems, and observability pipelines across three galactic missions.`,tags:[`Argo CD`,`Argo Rollouts`,`OpenTelemetry`,`Jaeger`,`PromQL`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,about:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`Welcome aboard the GitOps Starliner, a multi-species engineering vessel orbiting the vibrant planet of Polaris-9. Life in this quadrant is wonderfully diverse, from the whispering cloud-dwellers of Nebulon to the rhythmic click-speakers of Crustacea Prime.`,`Communication between species used to be seamless, thanks to the Echo Server, a universal translator that instantly echoed your words in the listener's native format.`,`But lately, something's off. Messages are getting scrambled. Some transmissions never arrive. The Echo Server, deployed across the Staging Moonbase and the Production Outpost, is no longer syncing properly. The Argo CD dashboard shows no active deployments, and telemetry is suspiciously quiet.`,`You've been assigned to restore interstellar communication before the next critical mission.`],levels:[{id:`beginner`,name:`Broken Echoes`,difficulty:`Beginner`,topics:[`Argo CD`],learnings:[`Debug GitOps flows with Argo CD`,`ApplicationSet templating & pitfalls`,`Environment isolation & namespaces`,`Sync policies: automated, prune & self-heal`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F01-echoes-lost-in-orbit_beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/adventure-01-echoes-lost-in-orbit-easy-broken-echoes/117/40`,deadline:`10 December 2025 at 09:00 CET`,intro:[`The Echo Server is down across both environments and messages are silent.`,`Investigate the Argo CD ApplicationSet configuration, spot the templating pitfalls, and restore proper multi-environment delivery to bring communications back online.`],backstory:[`The Echo Server is misbehaving. Both environments seem to be down, and messages are silent.`,`Your mission: investigate the Argo CD configuration and restore proper multi-environment delivery.`],objective:[`See two distinct Applications in the Argo CD dashboard (one per environment)`,`Ensure each Application deploys to its own isolated namespace`,`Make the system resilient so Argo CD automatically reverts manual cluster changes`,`Confirm that updates roll out automatically without leaving stale resources behind`],toolbox:[{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,body:`Wait around 5 minutes for the Codespace to provision a Kubernetes cluster, Argo CD, and the sample app. Press Cmd+Shift+P (or Ctrl+Shift+P on Windows/Linux) and search for 'View Creation Log' to track progress.`},{title:`Access Argo CD`,body:"Open the Ports tab, find port 30100 (Argo CD), and click the forwarded address. Log in with:\n\n```\nUsername: readonly\nPassword: a-super-secure-password\n```"},{title:`Fix the ApplicationSet`,body:`All errors are in this file:

\`\`\`
adventures/01-echoes-lost-in-orbit/beginner/manifests/appset.yaml
\`\`\`

This challenge uses Kustomize under the hood: a base set of manifests with environment-specific overlays (staging, prod). Argo CD detects and applies these automatically, so your focus is on fixing the ApplicationSet to properly reference the Kustomize-managed paths.

After making changes, apply them:

\`\`\`sh
kubectl apply -n argocd -f adventures/01-echoes-lost-in-orbit/beginner/manifests/appset.yaml
\`\`\``},{title:`Run the Smoke Test`,body:"Run the smoke test to verify your solution locally:\n\n```sh\nadventures/01-echoes-lost-in-orbit/beginner/smoke-test.sh\n```"}],verification:{command:`adventures/01-echoes-lost-in-orbit/beginner/smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`}},{id:`intermediate`,name:`The Silent Canary`,difficulty:`Intermediate`,topics:[`Argo Rollouts`,`PromQL`],learnings:[`Progressive delivery with Argo Rollouts`,`Canary deployments & automated analysis`,`Write PromQL queries for health validation`,`Kube-state-metrics for deployment decisions`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F01-echoes-lost-in-orbit_intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/adventure-01-echoes-lost-in-orbit-intermediate-the-silent-canary/310/8`,deadline:`24 December 2025 at 09:00 CET`,intro:[`A canary rollout is stuck and the Zephyrians are still waiting to communicate.`,`Debug the broken progressive delivery system by writing PromQL health checks that let Argo Rollouts automatically validate and advance the deployment.`],backstory:[`After fixing the communication outage in Level 1, the Intergalactic Union welcomed a new species: the Zephyrians.`,`The communications team attempted to deploy their language files using a progressive delivery system, but the rollout is failing. The Zephyrians are still waiting to communicate with the rest of the galaxy.`,`A previous engineer configured automated canary deployments with health checks but left the setup incomplete.`,`Your mission: debug the broken rollout and bring the Zephyrians' voices online.`],objective:[`Pod info version 6.9.3 deployed successfully in both staging and production environments`,`Rollouts automatically progress through canary stages based on health metrics`,`Two working PromQL queries in the AnalysisTemplate that validate application health during releases`,`All rollouts complete successfully`],toolbox:[{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`},{name:`Argo CD CLI`,description:`manage Argo CD applications from the command line`,url:`https://argo-cd.readthedocs.io/en/latest/user-guide/commands/argocd/`},{name:`Argo Rollouts kubectl plugin`,description:`extended kubectl commands for managing rollouts`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/kubectl-plugin/`}],howToPlay:[{title:`Wait for Infrastructure`,body:`Wait ~5-10 minutes for infrastructure to deploy. After it deploys, the setup script starts port forwarding to the Argo Rollouts dashboard, keeping a terminal busy. Open a new terminal to run commands.`},{title:`Access the Dashboards`,body:`Open the Ports tab. Log into Argo CD at port 30100:

\`\`\`
Username: readonly
Password: a-super-secure-password
\`\`\`

Access Argo Rollouts at port 30101 and Prometheus at port 30102.`},{title:`Fix the Manifests`,body:`Review and fix the configuration in \`adventures/01-echoes-lost-in-orbit/intermediate/manifests/\`.

This challenge uses Kustomize under the hood: a base set of manifests with environment-specific overlays (staging, prod). Argo CD detects and applies these automatically, so you don't need to run Kustomize commands manually.`},{title:`Deploy Your Changes`,body:`Commit and push your changes to trigger the deployment:

\`\`\`sh
git add adventures/01-echoes-lost-in-orbit/intermediate/manifests/
git commit -m "Fix configuration"
git push
\`\`\`

If pushing to a branch other than main, also update the ApplicationSet in \`appset.yaml\` to point to your branch.

Speed up Argo CD sync:

\`\`\`sh
argocd app get echo-server-staging --refresh
argocd app get echo-server-prod --refresh
\`\`\``},{title:`Trigger and Monitor the Rollout`,body:`After Argo CD syncs, retry the rollouts:

\`\`\`sh
kubectl argo rollouts retry rollout echo-server -n echo-staging
kubectl argo rollouts retry rollout echo-server -n echo-prod
\`\`\`

Watch canary progress (should advance 33% to 66% to 100%):

\`\`\`sh
kubectl argo rollouts get rollout echo-server -n echo-staging --watch
kubectl argo rollouts get rollout echo-server -n echo-prod --watch
\`\`\`

In real-world progressive delivery, staging is updated first, validated, and then changes are promoted to production. This challenge skips that separation so you can focus on the canary rollout mechanics and health checks without managing two promotion steps.`},{title:`Run the Smoke Test`,body:"Run the smoke test to verify your solution:\n\n```sh\nadventures/01-echoes-lost-in-orbit/intermediate/smoke-test.sh\n```"}],helpfulLinks:[{label:`Argo Rollouts documentation`,url:`https://argo-rollouts.readthedocs.io/en/stable/`},{label:`Analysis and progressive delivery`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/analysis/`},{label:`PromQL basics`,url:`https://prometheus.io/docs/prometheus/latest/querying/basics/`},{label:`kube-state-metrics exposed metrics`,url:`https://github.com/kubernetes/kube-state-metrics/tree/main/docs#exposed-metrics`}],verification:{command:`adventures/01-echoes-lost-in-orbit/intermediate/smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`}},{id:`expert`,name:`Hyperspace Operations & Transport`,difficulty:`Expert`,topics:[`Argo Rollouts`,`OpenTelemetry`,`Jaeger`,`PromQL`],learnings:[`Configure OpenTelemetry Collector pipelines`,`Spanmetrics connector (traces to metrics)`,`Detect idle canaries with traffic validation`,`Distributed tracing with Jaeger`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F01-echoes-lost-in-orbit_expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/adventure-01-echoes-lost-in-orbit-expert-hyperspace-operations-transport/351/4`,deadline:`14 January 2026 at 09:00 CET`,intro:[`The observability pipeline is broken and HotROD's canary can't validate.`,`Wire an OpenTelemetry Collector with spanmetrics to convert distributed traces into Prometheus metrics, then write PromQL queries that catch idle canaries, high error rates, and latency spikes before they reach production.`],backstory:[`After fixing the Zephyrian communications, word of your progressive release mastery spread across the galaxy. The Bytari, a highly advanced species from the Andromeda sector, were impressed.`,`They want to apply progressive delivery to their mission-critical service: HotROD (Hyperspace Operations & Transport, Rapid Orbital Dispatch), an interstellar ride-sharing service handling dispatch requests across thousands of star systems. Every millisecond of latency matters, and any error could strand travelers between dimensions.`,`A previous engineer started instrumenting HotROD with OpenTelemetry and configured Argo Rollouts for automated validation, but left the setup incomplete. The observability pipeline is broken. The Bytari don't use staging/production environments; they believe in single-environment progressive delivery validated purely by trace-derived metrics and automated health checks.`,`Your mission: fix the observability pipeline and canary validation. Make HotROD deployment-ready with proper distributed tracing.`],objective:[`Automated rollout progression to HotROD version 1.76.0 driven by observability signals`,`OpenTelemetry Collector configured with an OTLP receiver for HotROD traces, a Spanmetrics connector converting traces to metrics, trace export to Jaeger, and metrics export to Prometheus`,`Canary analysis with three PromQL queries: traffic detection (at least 0.05 req/s to prevent idle canaries), error rate below 5%, and 95th-percentile latency below 1000ms`],toolbox:[{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`},{name:`Argo CD CLI`,description:`manage Argo CD applications from the command line`,url:`https://argo-cd.readthedocs.io/en/latest/user-guide/commands/argocd/`},{name:`Argo Rollouts kubectl plugin`,description:`extended kubectl commands for managing rollouts`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/kubectl-plugin/`}],howToPlay:[{title:`Wait for Infrastructure`,body:`Wait ~5-10 minutes for infrastructure to deploy. Port forwarding starts automatically after infrastructure is ready, keeping a terminal busy. Open a new terminal to run commands.`},{title:`Access the Dashboards`,body:`Open the Ports tab. Log into Argo CD at port 30100:

\`\`\`
Username: readonly
Password: a-super-secure-password
\`\`\`

Access Argo Rollouts at 30101, Prometheus at 30102, and Jaeger at 30103.`},{title:`Fix the Manifests`,body:"Fix the manifests in `adventures/01-echoes-lost-in-orbit/expert/manifests/`. Use the Argo Rollouts dashboard, Prometheus UI, and Jaeger UI to debug and validate your changes."},{title:`Deploy Your Changes`,body:`Commit and push to trigger the deployment:

\`\`\`sh
git add adventures/01-echoes-lost-in-orbit/expert/manifests/
git commit -m "Fix configuration"
git push
\`\`\`

If pushing to a branch other than main, also update the ApplicationSet in \`appset.yaml\` to point to your branch.

Refresh Argo CD apps:

\`\`\`sh
argocd app get hotrod --refresh
argocd app get otel --refresh
\`\`\`

If you changed HotROD, retry the rollout:

\`\`\`sh
kubectl argo rollouts retry rollout hotrod -n hotrod
\`\`\`

If you changed the OTel Collector config, restart it:

\`\`\`sh
kubectl rollout restart daemonset/collector -n otel
\`\`\``},{title:`Watch the Rollout`,body:"Watch rollout progress. The rollout should progress automatically based on analysis metrics:\n\n```sh\nkubectl argo rollouts get rollout hotrod -n hotrod --watch\n```"},{title:`Run the Smoke Test`,body:"Run the smoke test to verify your solution:\n\n```sh\nadventures/01-echoes-lost-in-orbit/expert/smoke-test.sh\n```"}],helpfulLinks:[{label:`OpenTelemetry Collector configuration`,url:`https://opentelemetry.io/docs/collector/configuration/`},{label:`Span Metrics Connector`,url:`https://github.com/open-telemetry/opentelemetry-collector-contrib/tree/main/connector/spanmetricsconnector`},{label:`Argo Rollouts analysis`,url:`https://argo-rollouts.readthedocs.io/en/stable/features/analysis/`},{label:`PromQL basics`,url:`https://prometheus.io/docs/prometheus/latest/querying/basics/`}],verification:{command:`adventures/01-echoes-lost-in-orbit/expert/smoke-test.sh`,description:`Once you think you've solved the challenge, run the smoke test to verify your solution.`}}]},{id:`the-ai-observatory`,title:`The AI Observatory`,month:`FEB 2026`,story:`Investigate a mysterious bandwidth anomaly at a remote research station by instrumenting its AI system with OpenTelemetry, OpenLLMetry, and Jaeger.`,tags:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`,`Prometheus`,`Python`],contributor:{name:`Katharina Sick`,url:`https://ksick.dev/`,about:`DevRel at Dynatrace and co-organizer of Cloud Native Linz. Passionate about building user-friendly Cloud Native and Kubernetes solutions, with a background in mobile and backend development. Found in tech and sports communities, inline skating rinks, and quiz nights across Europe.`},backstory:[`You are stationed at Perimeter Alpha, a research outpost on the newly discovered planet HB-7742. The station is run by HubSystem, a central AI that manages everything from life support to data analysis.`,`Recently, the station's bandwidth usage has spiked to 847% above baseline, but no one knows why. As the systems engineer, it's your job to instrument the AI, trace its activities, and uncover the root cause of the anomaly.`,`Your mission: bring visibility to the station's AI and solve the mystery.`],levels:[{id:`beginner`,name:`Calibrating the Lens`,difficulty:`Beginner`,topics:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`],learnings:[`Instrument Python AI apps with OpenLLMetry`,`Analyze traces in Jaeger`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F03-the-ai-observatory_01-beginner%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/instrument-your-first-llm-adventure-03-beginner-is-live/865/8`,deadline:`8 March 2026 at 23:59 CET`,intro:[`Something is eating 847% of your station's bandwidth and nobody knows what. Instrument HubSystem with OpenLLMetry, send traces to the OpenTelemetry Collector, and use Jaeger to uncover what the AI is doing behind the scenes.`],backstory:[`You're a researcher stationed at Perimeter Alpha, a remote research outpost on the newly discovered planet HB-7742. Your team of six scientists is protected by a single SecUnit, assigned by the corporation to ensure your safety during the survey mission. All station queries flow through HubSystem, the central AI that manages everything from data analysis to status reports.`,`Three weeks in, you notice something odd in your morning diagnostics: communication module usage at 847% above baseline. Nobody's streaming. Nobody's running large data transfers. The planet surveys are on schedule. So what's consuming all that bandwidth?`,`As the station's systems engineer, you decide to investigate. Time to instrument HubSystem with OpenTelemetry and find out what's really going on.`,`Credits: The characters of this adventure are borrowed from the Murderbot Diaries series by Martha Wells, a brilliant series that is funny, action-packed, and surprisingly heartwarming. It follows a security unit that hacked its own governor module and now just wants to be left alone to watch media, but keeps getting pulled into human nonsense.`],objective:[`Enable OpenTelemetry instrumentation for HubSystem using OpenLLMetry`,`Send traces to the OpenTelemetry Collector at http://localhost:30107`,`Analyze traces in Jaeger to find what causes the high bandwidth usage`,`Provide the correct answer in quiz.txt`],architecture:[`All AI and observability infrastructure (Ollama, OpenTelemetry Collector, Jaeger) runs inside Kubernetes, while HubSystem runs as a local Python application outside the cluster.`,`This setup lets you focus on instrumentation without a build or deploy cycle: edit the Python code, run it, and see traces in Jaeger immediately.`],toolbox:[{name:`python`,description:`programming language used for the HubSystem application`},{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,body:`Wait ~10 minutes for all infrastructure to initialize.`},{title:`Open Jaeger`,body:`Open the Ports tab, find Jaeger at port 30103. This is where you will analyze the traces sent by HubSystem.`},{title:`Instrument the App`,body:`The application code is in \`./hubsystem.py\`. Add OpenTelemetry instrumentation using OpenLLMetry. The OTel
Collector and Jaeger are already configured correctly; you only need to instrument the app. You do not need to
interact with Kubernetes directly. The cluster is already running, so focus on the Python code.`},{title:`Run and Investigate`,body:"Run the application, interact with the AI to generate traces, then check Jaeger:\n\n```sh\nmake hubsystem\n```"},{title:`Answer the Quiz`,body:"Find the trace responsible for the high bandwidth usage and inspect its attributes to answer `quiz.txt`."}],helpfulLinks:[{label:`OpenLLMetry SDK for Python`,url:`https://traceloop.com/docs/openllmetry/getting-started-python`},{label:`Jaeger documentation`,url:`https://www.jaegertracing.io/docs/latest/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`}},{id:`intermediate`,name:`The Distracted Pilot`,difficulty:`Intermediate`,topics:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`,`Prometheus`],learnings:[`Instrument RAG pipelines with OpenLLMetry`,`Create custom OpenTelemetry metrics in Python`,`Write PromQL queries & recording rules in Prometheus`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F03-the-ai-observatory_02-intermediate%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/instrument-debug-a-rag-pipeline-adventure-03-intermediate-is-live/936/2`,deadline:`8 March 2026 at 23:59 CET`,intro:[`ART's RAG pipeline is retrieving entertainment data instead of navigation coordinates and won't calculate your jump. Instrument the full retrieval pipeline with OpenLLMetry, build a custom OTel metric to quantify the distraction, and write a Prometheus recording rule to prove it.`],backstory:[`You're a rogue SecUnit who just escaped from Preservation Station after being identified. A researcher helped you flee aboard the Perihelion, a university research vessel with a very opinionated AI.`,`The ship's AI agreed to help you disappear. You've nicknamed it ART. The plan: jump to RaviHyral, lay low, and figure out your next move. Except ART was supposed to have the jump coordinates ready an hour ago.`,`You ping the ship's AI through your internal comm.

SecUnit: "ART. Jump coordinates. Now."

ART: "I'm multitasking. The coordinates are... being compiled."

That's not normal. ART is never vague. You access the ship's diagnostic systems (something you're not supposed to be able to do, but ART hasn't locked you out yet).`,`Your mission: diagnose ART's distraction using OpenTelemetry and fix the navigation system before you miss your jump.`,`Credits: The characters of this adventure are borrowed from the Murderbot Diaries series by Martha Wells, a brilliant series that is funny, action-packed, and surprisingly heartwarming. It follows a security unit that hacked its own governor module and now just wants to be left alone to watch media, but keeps getting pulled into human nonsense.`],objective:[`Instrument the full RAG pipeline with OpenLLMetry (add a span named rag.context_assembly with attribute context.categories)`,`Implement a custom metric art.rag.retrieval.count to track how often ART retrieves entertainment vs navigation data`,`Create a Prometheus recording rule to calculate ART's Distraction Ratio`,`Restore the navigation system so ART successfully calculates jump coordinates to RaviHyral`],architecture:[`The ART Pilot System runs as a local Python application outside Kubernetes, using a RAG (Retrieval-Augmented Generation) architecture. AI infrastructure (Ollama for LLM, Qdrant for vector storage) and observability tools (OpenTelemetry Collector, Jaeger, Prometheus) run inside Kubernetes.`,`This setup lets you focus on observability patterns: edit Python code, run it, and see traces and metrics immediately without a build or deploy cycle.`],toolbox:[{name:`python`,description:`programming language used for the ART application`},{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,body:`Wait ~15 minutes for all infrastructure to initialize.`},{title:`Access Observability Tools`,body:`Open the Ports tab: Prometheus at port 30102, Jaeger at port 30103.`},{title:`Instrument and Configure`,body:"The application code is in `./art.py`. Instrument it with OpenLLMetry and add the custom metric. The Prometheus recording rules are in `./manifests/prometheus-rule.yaml`. After changing the rule file, apply it to the cluster:\n\n```sh\nmake apply\n```"},{title:`Generate Traffic`,body:`Run the application to interact with ART ("Calculate jump"), or generate continuous traffic for your metric graphs:

\`\`\`sh
make art
# or for continuous traffic:
make traffic
\`\`\``},{title:`Fix the Navigation`,body:`Verify traces in Jaeger and the recording rule in Prometheus. Fix the navigation system so ART returns jump coordinates to RaviHyral.`}],helpfulLinks:[{label:`OpenLLMetry SDK for Python`,url:`https://traceloop.com/docs/openllmetry/getting-started-python`},{label:`OpenTelemetry Python metrics`,url:`https://opentelemetry.io/docs/languages/python/instrumentation/#metrics`},{label:`Prometheus recording rules`,url:`https://prometheus.io/docs/prometheus/latest/configuration/recording_rules/`},{label:`Qdrant filtering`,url:`https://qdrant.tech/documentation/concepts/filtering/`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`}},{id:`expert`,name:`The Noise Filter`,difficulty:`Expert`,topics:[`OpenTelemetry`,`OpenLLMetry`,`Jaeger`],learnings:[`OpenTelemetry GenAI semantic conventions`,`Tail sampling in the OTel Collector`],codespacesUrl:`${e}?devcontainer_path=.devcontainer%2F03-the-ai-observatory_03-expert%2Fdevcontainer.json&quickstart=1`,discussionUrl:`${t}/t/reduce-telemetry-noise-adventure-03-expert-is-live/999/1`,deadline:`8 March 2026 at 23:59 CET`,intro:[`ART is flooding Jaeger with 40,000 non-standard spans an hour. Fix the chat span to follow OpenTelemetry GenAI semantic conventions with proper token usage attributes, then configure tail sampling in the Collector to keep only traces that contain errors or exceed 5 seconds.`],backstory:[`You made it to RaviHyral. The Perihelion docked at Outpost Verada, a small independent research station run by a loose collective of academics who agreed to look the other way. In exchange, ART offered to share its observability data with the station's monitoring team.`,`That was three hours ago. Now the station's lead engineer is at your docking port, looking annoyed.

Engineer: "Your ship's AI is flooding our Jaeger instance. Do you have any idea how many spans it's generating? We can't find anything in there."

SecUnit: "ART."

ART: "Comprehensive telemetry is a feature."

Engineer: "It's 40,000 spans an hour. Every healthy query. Every token. It doesn't even follow conventions. We only care about failures and anomalies, the things that actually need attention."

SecUnit: "ART. Fix it."

ART: "...Fine."`,`The engineer hands you access to the collector config and the application code, then walks away. Two problems to fix. ART's spans don't follow OTel GenAI semantic conventions, and the collector is forwarding everything.`,`Credits: The characters of this adventure are borrowed from the Murderbot Diaries series by Martha Wells, a brilliant series that is funny, action-packed, and surprisingly heartwarming. It follows a security unit that hacked its own governor module and now just wants to be left alone to watch media, but keeps getting pulled into human nonsense.`],objective:[`Fix ART's chat span to follow OpenTelemetry GenAI semantic conventions, including token usage attributes`,`Configure tail sampling in the OpenTelemetry Collector to keep only traces that contain errors or take longer than 5 seconds`],architecture:[`Same setup as the intermediate level: the ART Pilot System runs as a local Python application outside Kubernetes with a RAG architecture. AI infrastructure (Ollama, Qdrant) and observability tools (OpenTelemetry Collector, Jaeger) run inside Kubernetes.`],toolbox:[{name:`python`,description:`programming language used for the ART application`},{name:`kubectl`,description:`Kubernetes CLI for interacting with the cluster`,url:`https://kubernetes.io/docs/reference/kubectl/`},{name:`kubens`,description:`fast way to switch between Kubernetes namespaces`,url:`https://github.com/ahmetb/kubectx`},{name:`k9s`,description:`terminal UI for managing and inspecting your cluster`,url:`https://k9scli.io/`}],howToPlay:[{title:`Wait for Infrastructure`,body:`Wait ~15 minutes for all infrastructure to initialize.`},{title:`Open Jaeger`,body:`Open the Ports tab, find Jaeger at port 30103. Verify your spans look correct and that sampling works as expected.`},{title:`Fix Instrumentation and Sampling`,body:"Fix two things:\n\n1. The application code in `./art.py`: update the `chat` span to follow OpenTelemetry GenAI semantic conventions, including token usage attributes.\n2. The collector config in `./manifests/otel-collector-config.yaml`: configure tail sampling to keep only traces that contain errors or take longer than 5 seconds."},{title:`Apply and Test`,body:"After changing `art.py`, restart traffic to pick up new instrumentation. After changing the collector config, apply it:\n\n```sh\nkubectl apply -f manifests/otel-collector-config.yaml -n otel\nkubectl rollout restart deployment/collector -n otel\n```\n\nThen generate traces:\n\n```sh\nmake traffic\n```\n\nVerify in Jaeger that spans follow conventions and only errors and slow traces appear."}],helpfulLinks:[{label:`OpenTelemetry GenAI semantic conventions`,url:`https://opentelemetry.io/docs/specs/semconv/gen-ai/gen-ai-spans/`},{label:`OpenTelemetry Python: recording exceptions`,url:`https://opentelemetry.io/docs/languages/python/instrumentation/#record-exceptions`},{label:`OTel Collector tail sampling processor`,url:`https://github.com/open-telemetry/opentelemetry-collector-contrib/tree/main/processor/tailsamplingprocessor`},{label:`Python contextlib.contextmanager`,url:`https://docs.python.org/3/library/contextlib.html#contextlib.contextmanager`}],verification:{command:`./verify.sh`,description:`Once you think you've solved the challenge, run the verification script. If it fails it will tell you which checks didn't pass. If it passes, it generates a Certificate of Completion you can paste into the discussion.`}}]}],r=Array.from(new Set(n.flatMap(e=>e.tags))).sort(),i=Object.values(n.filter(e=>e.contributor!==void 0).reduce((e,t)=>{let n=t.contributor.name;return e[n]||(e[n]={name:t.contributor.name,url:t.contributor.url,about:t.contributor.about,adventures:[]}),e[n].adventures.push({id:t.id,title:t.title}),e},{})),a=e=>n.filter(t=>t.tags.includes(e)).flatMap(e=>e.levels.map(t=>({level:t,adventureId:e.id,adventureTitle:e.title}))),o=e=>e.toLowerCase().replace(/[^a-z0-9]+/g,`-`).replace(/(^-|-$)/g,``),s=Object.fromEntries(r.map(e=>[o(e),e])),c=e=>s[e];export{c as a,a as i,i as n,o,r,n as t};